 21→
 22→namespace MicroCommerce.ApiService.Tests.Integration.Fixtures;
 23→
 24→/// <summary>
 25→/// Custom WebApplicationFactory for integration tests.
 26→/// Replaces production dependencies with test equivalents:
 27→/// - PostgreSQL: Testcontainers instance (replaces Aspire Npgsql integration)
 28→/// - MassTransit: In-memory test harness (replaces Azure Service Bus transport)
 29→/// - Azure Blob Storage: No-op stub (image upload not tested here)
 30→/// - Background services: Disabled (data seeders, cleanup services)
 31→/// - Keycloak JWT: Replaced with FakeAuthenticationHandler
 32→/// </summary>
 33→public class ApiWebApplicationFactory : WebApplicationFactory<Program>, IAsyncLifetime
 34→{
 35→    private static readonly SoftDeleteInterceptor _softDeleteInterceptor = new();
 36→    private static readonly ConcurrencyInterceptor _concurrencyInterceptor = new();
 37→    private static readonly AuditInterceptor _auditInterceptor = new();
 38→
 39→    private readonly PostgreSqlContainer _dbContainer;
 40→
 41→    public ApiWebApplicationFactory()
 42→    {
 43→        _dbContainer = new PostgreSqlBuilder("postgres:15-alpine")
 44→            .WithDatabase("microcommerce_test")
 45→            .WithCleanUp(true)
 46→            .Build();
 47→    }
 48→
 49→    protected override void ConfigureWebHost(IWebHostBuilder builder)
 50→    {
 51→        builder.ConfigureServices(services =>
 52→        {
 53→            // Remove all hosted services (data seeders, background cleanup)
 54→            // These interfere with test isolation and are not needed for API tests
 55→            System.Collections.Generic.List<ServiceDescriptor> hostedServices = services
 56→                .Where(d => d.ServiceType == typeof(IHostedService))
 57→                .ToList();
 58→
 59→            foreach (ServiceDescriptor service in hostedServices)
 60→            {
 61→                services.Remove(service);
 62→            }
 63→
 64→            // MassTransit registers 'masstransit-bus' health checks via IConfigureOptions<HealthCheckServiceOptions>.
 65→            // When AddMassTransitTestHarness is called, it re-registers the same checks, causing:
 66→            //   "Duplicate health checks were registered with the name(s): masstransit-bus"
 67→            // Fix: Add a PostConfigure action that deduplicates health check registrations by name.
 68→            // This runs after all IConfigureOptions<HealthCheckServiceOptions> have applied, removing any dupes.
 69→            services.PostConfigure<Microsoft.Extensions.Diagnostics.HealthChecks.HealthCheckServiceOptions>(opts =>
 70→            {
 71→                System.Collections.Generic.HashSet<string> seen = new(StringComparer.OrdinalIgnoreCase);
 72→                System.Collections.Generic.List<HealthCheckRegistration> duplicates = [];
 73→                foreach (HealthCheckRegistration r in opts.Registrations)
 74→                {
 75→                    if (!seen.Add(r.Name))
 76→                    {
 77→                        duplicates.Add(r);
 78→                    }
 79→                }
 80→                foreach (HealthCheckRegistration duplicate in duplicates)
 81→                {
 82→                    opts.Registrations.Remove(duplicate);
 83→                }
 84→            });
 85→
 86→            // Replace all DbContext registrations with Testcontainer connection string.
 87→            // Aspire's AddNpgsqlDbContext uses AddDbContextPool which registers additional pool-related
 88→            // services (IDbContextOptionsConfiguration<T>, IDbContextPool<T>, IScopedDbContextLease<T>)
 89→            // that must all be removed to prevent the Aspire connection string validator from running.
 90→            // We remove ALL pool-related descriptors for each DbContext type, then re-register with
 91→            // AddDbContext (non-pooled) pointing at the Testcontainer connection string.
 92→
 93→            ReplaceDbContext<CatalogDbContext>(services, "catalog");
 94→            ReplaceDbContext<CartDbContext>(services, "cart");
 95→            ReplaceDbContext<OrderingDbContext>(services, "ordering");
 96→            ReplaceDbContext<InventoryDbContext>(services, "inventory");
 97→            ReplaceDbContext<ProfilesDbContext>(services, "profiles");
 98→            ReplaceDbContext<ReviewsDbContext>(services, "reviews");
 99→            ReplaceDbContext<WishlistsDbContext>(services, "wishlists");
100→
101→            // Replace MassTransit with in-memory test harness.
102→            // The primary challenge is BusDepot.ctor(IEnumerable<IBusInstance>) which throws
103→            // "An item with the same key has already been added. Key: MassTransit.IBus"
104→            // when both the production Azure Service Bus instance AND the test harness bus instance
105→            // are registered as IBusInstance in the DI container.
106→            //
107→            // services.RemoveAll(IBus/IBusControl/IPublishEndpoint/ISendEndpointProvider) removes 4 services
108→            // but leaves 3 bus-instance-related registrations that cause duplicates:
109→            //   1. MassTransit.Transports.IBusInstance
110→            //   2. MassTransit.DependencyInjection.Bind<IBus, IBusInstance>
111→            //   3. MassTransit.IBusDepot
112→            // These 3 must also be removed before AddMassTransitTestHarness adds its own versions.
113→            services.RemoveAll(typeof(IBus));
114→            services.RemoveAll(typeof(IBusControl));
115→            services.RemoveAll(typeof(IPublishEndpoint));
116→            services.RemoveAll(typeof(ISendEndpointProvider));
117→
118→            System.Collections.Generic.List<ServiceDescriptor> busInstanceDescriptors = services
119→                .Where(d => d.ServiceType.FullName?.Equals("MassTransit.Transports.IBusInstance", StringComparison.Ordinal) == true
120→                    || d.ServiceType.FullName?.StartsWith("MassTransit.DependencyInjection.Bind`2", StringComparison.Ordinal) == true
121→                    || d.ServiceType.FullName?.Equals("MassTransit.IBusDepot", StringComparison.Ordinal) == true)
122→                .ToList();
123→            foreach (ServiceDescriptor descriptor in busInstanceDescriptors)
124→            {
125→                services.Remove(descriptor);
126→            }
127→
128→            services.AddMassTransitTestHarness(cfg =>
129→            {
130→                cfg.AddConsumers(typeof(Program).Assembly);
131→            });
132→
133→            // Replace Azure Blob Storage with no-op stub
134→            // Integration tests don't upload images, so we can use a null implementation
135→            services.RemoveAll<IImageUploadService>();
136→            services.AddScoped<IImageUploadService, NoOpImageUploadService>();
137→
138→            // Replace Azure Avatar service with no-op stub
139→            services.RemoveAll<IAvatarImageService>();
140→            services.AddScoped<IAvatarImageService, NoOpAvatarImageService>();
141→
142→            // Replace Keycloak JWT auth with fake handler for tests
143→            // FakeAuthenticationHandler reads X-Test-UserId header and injects claims
144→            services.AddAuthentication(FakeAuthenticationHandler.SchemeName)
145→                .AddScheme<AuthenticationSchemeOptions, FakeAuthenticationHandler>(
146→                    FakeAuthenticationHandler.SchemeName, options => { });
147→        });
148→
149→        builder.UseEnvironment("Testing");
150→    }
151→
152→    /// <summary>
153→    /// Removes all pool-related service registrations for the given DbContext type
154→    /// (registered by Aspire's AddNpgsqlDbContext/AddDbContextPool) and re-registers
155→    /// the context with AddDbContext pointing at the Testcontainer connection string.
156→    /// </summary>
157→    private void ReplaceDbContext<TContext>(IServiceCollection services, string schema)
158→        where TContext : DbContext
159→    {
160→        // Remove all service descriptors related to this DbContext type.
161→        // AddDbContextPool registers: DbContextOptions<T>, IDbContextOptionsConfiguration<T>,
162→        // IDbContextPool<T> (internal), IScopedDbContextLease<T> (internal), and T itself.
163→        // We use FullName string matching for internal types to avoid EF1001 errors.
164→        string contextTypeName = typeof(TContext).FullName ?? typeof(TContext).Name;
165→        System.Collections.Generic.List<ServiceDescriptor> descriptorsToRemove = services
166→            .Where(d =>
167→                d.ServiceType == typeof(DbContextOptions<TContext>) ||
168→                d.ServiceType == typeof(IDbContextOptionsConfiguration<TContext>) ||
169→                d.ServiceType == typeof(TContext) ||
170→                // Internal EF Core pool types — matched by FullName to avoid EF1001 errors
171→                (d.ServiceType.IsGenericType &&
172→                    (d.ServiceType.GetGenericTypeDefinition().FullName?.StartsWith("Microsoft.EntityFrameworkCore.Internal.IDbContextPool", StringComparison.Ordinal) == true ||
173→                     d.ServiceType.GetGenericTypeDefinition().FullName?.StartsWith("Microsoft.EntityFrameworkCore.Internal.IScopedDbContextLease", StringComparison.Ordinal) == true) &&
174→                    d.ServiceType.GenericTypeArguments.Length == 1 &&
175→                    d.ServiceType.GenericTypeArguments[0].FullName == contextTypeName))
176→            .ToList();
177→
178→        foreach (ServiceDescriptor descriptor in descriptorsToRemove)
179→        {
180→            services.Remove(descriptor);
181→        }
182→
183→        services.AddDbContext<TContext>(options =>
184→        {
185→            options.UseNpgsql(_dbContainer.GetConnectionString(), npgsql =>
186→                npgsql.MigrationsHistoryTable("__EFMigrationsHistory", schema));
187→            options.UseSnakeCaseNamingConvention();
188→            options.AddInterceptors(_softDeleteInterceptor, _concurrencyInterceptor, _auditInterceptor);
189→        });
190→    }
191→
192→    public async Task InitializeAsync()
193→    {
194→        // Start the PostgreSQL container
195→        await _dbContainer.StartAsync();
196→
197→        // Apply migrations for all DbContexts.
198→        // MigrateAsync is used instead of EnsureCreated because multiple DbContexts share one PostgreSQL
199→        // database (each uses a separate schema). EnsureCreated skips if ANY tables exist in the DB,
200→        // so only the first context's schema would be created. MigrateAsync applies each context's
201→        // migrations independently via separate __EFMigrationsHistory tables (one per schema).
202→        using Microsoft.Extensions.DependencyInjection.IServiceScope scope = Services.CreateScope();
203→
204→        CatalogDbContext catalogDb = scope.ServiceProvider.GetRequiredService<CatalogDbContext>();
205→        await catalogDb.Database.MigrateAsync();
206→
207→        CartDbContext cartDb = scope.ServiceProvider.GetRequiredService<CartDbContext>();
208→        await cartDb.Database.MigrateAsync();
209→
210→        OrderingDbContext orderingDb = scope.ServiceProvider.GetRequiredService<OrderingDbContext>();
211→        await orderingDb.Database.MigrateAsync();
212→
213→        InventoryDbContext inventoryDb = scope.ServiceProvider.GetRequiredService<InventoryDbContext>();
214→        await inventoryDb.Database.MigrateAsync();
215→
216→        ProfilesDbContext profilesDb = scope.ServiceProvider.GetRequiredService<ProfilesDbContext>();
217→        await profilesDb.Database.MigrateAsync();
218→
219→        ReviewsDbContext reviewsDb = scope.ServiceProvider.GetRequiredService<ReviewsDbContext>();
220→        await reviewsDb.Database.MigrateAsync();
221→
222→        WishlistsDbContext wishlistsDb = scope.ServiceProvider.GetRequiredService<WishlistsDbContext>();
223→        await wishlistsDb.Database.MigrateAsync();
224→    }
225→
226→    public new async Task DisposeAsync()
227→    {
228→        await _dbContainer.DisposeAsync();
229→        await base.DisposeAsync();
230→    }
231→}
